const config = {
  googleSheetId: 'YOUR_GOOGLE_SHEET_ID',
  googleSheetName: 'urls',
  logSheetId: 'YOUR_LOG_SHEET_ID',
  logSheetName: 'log',
  notionDatabaseId: 'YOUR_NOTION_DATABASE_ID',
  slackChannel: 'YOUR_SLACK_CHANNEL',
  maxArticles: 10,
  briefingPrompt: 'You are a professional news analyst. Read the article text provided and write a structured briefing. Return only a JSON object with these exact keys: headline (string, max 12 words), summary (string, 2 sentences), why_it_matters (string, 1 sentence), relevance_score (integer 1-10). Do not include any text outside the JSON object.',
  digestIntro: 'Daily AI news briefing is ready. Here are the top stories for today.'
};

return [{ json: config }];

const rawHtml = $input.item.json.data || '';
const url = $input.item.json.url || $('Read URL List from Sheets').item.json.url || '';

// Strip HTML tags without regex lookbehind
const noScript = rawHtml.split('<script').map(function(p, i) { return i === 0 ? p : p.split('</script>').slice(1).join('</script>'); }).join('');
const noStyle = noScript.split('<style').map(function(p, i) { return i === 0 ? p : p.split('</style>').slice(1).join('</style>'); }).join('');
const noTags = noStyle.replace(/<[^>]+>/g, ' ');
const decoded = noTags.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ');
const clean = decoded.replace(/\s+/g, ' ').trim();
const truncated = clean.length > 4000 ? clean.slice(0, 4000) + '...' : clean;

return [{
  json: {
    url: url,
    articleText: truncated,
    charCount: truncated.length
  }
}];

