const raw = $input.item.json.text || '';
const url = $('Prepare Article Text').item.json.url || '';

let briefing = { headline: 'No headline', summary: '', why_it_matters: '', relevance_score: 5 };

try {
  const startBrace = raw.indexOf('{');
  const endBrace = raw.lastIndexOf('}');
  if (startBrace !== -1 && endBrace !== -1) {
    const jsonStr = raw.slice(startBrace, endBrace + 1);
    briefing = JSON.parse(jsonStr);
  }
} catch (e) {
  briefing.summary = 'Could not parse Claude response';
}

return [{
  json: {
    url: url,
    headline: briefing.headline || 'No headline',
    summary: briefing.summary || '',
    why_it_matters: briefing.why_it_matters || '',
    relevance_score: briefing.relevance_score || 5,
    processedAt: new Date().toISOString()
  }
}];

const items = $input.item.json.data || [];
const today = new Date().toDateString();

const lines = items.map(function(item, i) {
  const rank = i + 1;
  const score = item.relevance_score || '?';
  const hl = item.headline || 'No headline';
  const summ = item.summary || '';
  const url = item.url || '';
  return rank + '. [Score: ' + score + '/10] ' + hl + ' -- ' + summ + ' Source: ' + url;
});

const message = 'Daily AI News Briefing | ' + today + '\n' + lines.join('\n\n');

return [{ json: { message: message, count: items.length } }];
